import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import API from '../services/api';
import './AdminAnalytics.css';

function AdminAnalytics() {
  const { user } = useAuth();
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [period, setPeriod] = useState('week');

  // Данные - только то, что реально работает
  const [listings, setListings] = useState([]);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    setError(null);

    try {
      // Используем ТОЛЬКО рабочий эндпоинт из listings
      const response = await API.get('/listings/?limit=100');
      setListings(response.data);

    } catch (err) {
      console.error('Ошибка:', err);
      setError('Не удалось загрузить данные');
    } finally {
      setLoading(false);
    }
  };

  // Вычисляем аналитику на фронтенде из полученных данных
  const calculateStats = () => {
    if (!listings.length) return null;

    const activeListings = listings.filter(l => l.listing_status_id === 1);
    const prices = activeListings.map(l => l.price).filter(p => p);

    // Средняя цена
    const avgPrice = prices.length
      ? prices.reduce((sum, p) => sum + p, 0) / prices.length
      : 0;

    // Цена за м² (упрощенно)
    const listingsWithArea = activeListings.filter(l => l.total_area && l.total_area > 0);
    const pricePerM2 = listingsWithArea.length
      ? listingsWithArea.reduce((sum, l) => sum + (l.price / l.total_area), 0) / listingsWithArea.length
      : 0;

    // Группировка по типу (упрощенно)
    const byType = {};
    activeListings.forEach(l => {
      const type = l.property_type?.name || 'Другое';
      if (!byType[type]) {
        byType[type] = { count: 0, totalPrice: 0, prices: [] };
      }
      byType[type].count++;
      if (l.price) {
        byType[type].totalPrice += l.price;
        byType[type].prices.push(l.price);
      }
    });

    const byTypeArray = Object.keys(byType).map(type => ({
      type,
      count: byType[type].count,
      avgPrice: byType[type].prices.length
        ? byType[type].totalPrice / byType[type].prices.length
        : 0
    }));

    return {
      totalListings: listings.length,
      activeListings: activeListings.length,
      avgPrice,
      pricePerM2,
      byType: byTypeArray
    };
  };

  if (!user || user.role_id !== 1) {
    return (
      <div className="analytics-error">
        <h2>🚫 Доступ запрещен</h2>
        <p>Только для администраторов</p>
      </div>
    );
  }

  if (loading) return <div className="loader">Загрузка...</div>;
  if (error) return <div className="error">{error}</div>;

  const stats = calculateStats();

  return (
    <div className="analytics-page">
      <h1>📊 Аналитика</h1>

      {/* Кнопки периода (просто для вида, пока не работают) */}
      <div className="period-selector">
        <button className={period === 'day' ? 'active' : ''}>День</button>
        <button className={period === 'week' ? 'active' : ''}>Неделя</button>
        <button className={period === 'month' ? 'active' : ''}>Месяц</button>
      </div>

      {stats && (
        <>
          {/* Сводка */}
          <div className="metrics-grid">
            <div className="metric-card">
              <h3>Всего объявлений</h3>
              <p className="metric-value">{stats.totalListings}</p>
            </div>
            <div className="metric-card">
              <h3>Активных</h3>
              <p className="metric-value">{stats.activeListings}</p>
            </div>
            <div className="metric-card">
              <h3>Средняя цена</h3>
              <p className="metric-value">{Math.round(stats.avgPrice).toLocaleString()} ₽</p>
            </div>
            <div className="metric-card">
              <h3>Цена за м²</h3>
              <p className="metric-value">{Math.round(stats.pricePerM2).toLocaleString()} ₽</p>
            </div>
          </div>

          {/* По типам */}
          <div className="analytics-card">
            <h2>🏠 По типам недвижимости</h2>
            <table className="stats-table">
              <thead>
                <tr>
                  <th>Тип</th>
                  <th>Количество</th>
                  <th>Средняя цена</th>
                </tr>
              </thead>
              <tbody>
                {stats.byType.map((item, idx) => (
                  <tr key={idx}>
                    <td>{item.type}</td>
                    <td>{item.count}</td>
                    <td>{Math.round(item.avgPrice).toLocaleString()} ₽</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* Последние объявления */}
          <div className="analytics-card">
            <h2>📋 Последние 10 объявлений</h2>
            <div className="listings-list">
              {listings.slice(0, 10).map((item, index) => (
                <div key={item.listing_id || index} className="listing-item">
                  <span className="rank">{index + 1}</span>
                  <div className="listing-info">
                    <h4>{item.title || 'Без названия'}</h4>
                    <p>{item.address || 'Адрес не указан'}</p>
                  </div>
                  <div className="listing-stats">
                    <span className="price">
                      {item.price ? item.price.toLocaleString() : 0} ₽
                    </span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </>
      )}
    </div>
  );
}

export default AdminAnalytics;
